function setCookie(e,t,o){var i="";if(o){var a=new Date;a.setTime(a.getTime()+o*24*60*60*1e3);i="; expires="+a.toUTCString()}document.cookie=e+"="+(t||"")+i+"; path=/"}function getCookie(e){var t=e+"=";var o=document.cookie.split(";");for(var i=0;i<o.length;i++){var a=o[i];while(a.charAt(0)==" "){a=a.substring(1,a.length)}if(a.indexOf(t)==0){return a.substring(t.length,a.length)}}return null}function eraseCookie(e){document.cookie=e+"=; Max-Age=-99999999;"}jQuery(document).inactivity({timeout:drupalSettings.inactive_autologout.timeout,mouse:true,keyboard:true,touch:true,customEvents:"",triggerAll:true});jQuery(document).on("activity",function(){if(drupalSettings.inactive_autologout.enable==1){if(drupalSettings.inactive_autologout.execute){var e=getCookie("localtimestamp");if(e==null){setCookie("localtimestamp",jQuery.now(),1)}e=parseInt(e)+parseInt(2e4);if(e<jQuery.now()){setCookie("localtimestamp",jQuery.now(),1);jQuery.ajax({url:drupalSettings.baseUrl+"/autologout_active?localtimestamp="+e,cache:false,success:function(e){setCookie("servertimestamp",e.timestamp,1)}})}}}});jQuery(document).on("inactivity",function(){var e=getCookie("servertimestamp");if(e!=null){jQuery.ajax({url:drupalSettings.baseUrl+"/autologout_gettimestamp",cache:false,success:function(e){setCookie("servertimestamp",e.timestamp,1)}});var t=parseInt(drupalSettings.inactive_autologout.timeout)+parseInt(getCookie("servertimestamp"));if(t<jQuery.now()){window.location.replace(drupalSettings.baseUrl+"/autologout")}}});